/**
 * update_clientes_hycite.ts
 * Actualiza datos de clientes en FlowSuiteCRM desde lista Hy-Cite pegada manualmente.
 * Upsert por hycite_id — solo actualiza, NO borra registros existentes.
 *
 * Uso:
 *   SUPABASE_URL=https://... SUPABASE_SERVICE_ROLE_KEY=... npx ts-node tools/update_clientes_hycite.ts
 *   Agregar --dry-run para solo ver los cambios sin escribir.
 */

import * as dotenv from 'dotenv'
import { createClient } from '@supabase/supabase-js'
dotenv.config()

const SUPABASE_URL = process.env.SUPABASE_URL ?? process.env.VITE_SUPABASE_URL ?? ''
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY ?? process.env.SUPABASE_SERVICE_KEY ?? ''
const DRY_RUN = process.argv.includes('--dry-run')

if (!SUPABASE_URL || !SUPABASE_KEY) {
  console.error('❌ Faltan SUPABASE_URL y SUPABASE_SERVICE_ROLE_KEY')
  console.error('   Ejecuta: SUPABASE_URL=https://... SUPABASE_SERVICE_ROLE_KEY=eyJ... npx ts-node tools/update_clientes_hycite.ts')
  process.exit(1)
}

const supabase = createClient(SUPABASE_URL, SUPABASE_KEY, { auth: { persistSession: false } })

// ── Helpers ───────────────────────────────────────────────────────────────────

function parseMonto(raw: string): number {
  return parseFloat(raw.replace(/[$,\s]/g, '').replace(' USD', '')) || 0
}

function cleanPhone(raw: string): string | null {
  const d = raw.replace(/\D/g, '')
  if (d.length < 7) return null
  // Formato limpio: ###-###-####
  if (d.length === 10) return `${d.slice(0,3)}-${d.slice(3,6)}-${d.slice(6)}`
  if (d.length === 11 && d[0] === '1') return `${d.slice(1,4)}-${d.slice(4,7)}-${d.slice(7)}`
  return raw.trim() || null
}

function cleanEmail(raw: string): string | null {
  const e = raw.trim().toLowerCase()
  return e.includes('@') ? e : null
}

type EstadoCuenta = 'actual' | 'cancelacion_total' | 'cargo_de_vuelta' | 'inactivo'

function parseEstado(raw: string): {
  estado_cuenta: EstadoCuenta
  estado_operativo: 'activo' | 'inactivo' | 'cancelado'
  estado_morosidad: string | null
  dias_atraso: number
  estado_cuenta_raw: string
} {
  const r = raw.trim()
  const base = { estado_cuenta_raw: r }

  if (/cancelaci[oó]n total/i.test(r) || /cancelada?/i.test(r))
    return { ...base, estado_cuenta: 'cancelacion_total', estado_operativo: 'cancelado', estado_morosidad: null, dias_atraso: 0 }

  if (/inactiv/i.test(r))
    return { ...base, estado_cuenta: 'inactivo', estado_operativo: 'inactivo', estado_morosidad: null, dias_atraso: 0 }

  if (/cargo de vuelta/i.test(r))
    return { ...base, estado_cuenta: 'cargo_de_vuelta', estado_operativo: 'activo', estado_morosidad: null, dias_atraso: 0 }

  if (/0.*30|0 a 30/i.test(r))
    return { ...base, estado_cuenta: 'actual', estado_operativo: 'activo', estado_morosidad: '0-30', dias_atraso: 1 }

  if (/31.*60|31 a 60/i.test(r))
    return { ...base, estado_cuenta: 'actual', estado_operativo: 'activo', estado_morosidad: '31-60', dias_atraso: 31 }

  if (/61.*90|61 a 90/i.test(r))
    return { ...base, estado_cuenta: 'actual', estado_operativo: 'activo', estado_morosidad: '61-90', dias_atraso: 61 }

  if (/9[01]\+|sobre 90|m[aá]s de 90/i.test(r))
    return { ...base, estado_cuenta: 'actual', estado_operativo: 'activo', estado_morosidad: '91+', dias_atraso: 91 }

  // "Actual" / "Elegible para Agregado" / default
  return { ...base, estado_cuenta: 'actual', estado_operativo: 'activo', estado_morosidad: null, dias_atraso: 0 }
}

