// ── Main ──────────────────────────────────────────────────────────────────────

async function run() {
  console.log(`\n${ DRY_RUN ? '🔍 DRY-RUN — sin cambios en BD' : '🚀 Actualizando clientes en Supabase' }\n`)

  // Buscar org_id (tomamos el primero disponible para esta organización)
  const { data: firstCliente } = await supabase
    .from('clientes')
    .select('org_id')
    .not('hycite_id', 'is', null)
    .limit(1)
    .single()

  const orgId = firstCliente?.org_id
  if (!orgId) { console.error('❌ No se encontró org_id en clientes existentes.'); process.exit(1) }
  console.log(`✅ org_id detectado: ${orgId}\n`)

  let updated = 0
  let notFound = 0
  const errors: string[] = []

  for (const row of RAW_DATA) {
    const [hyciteId, nombre, apellido, emailRaw, telA, telB, saldoRaw, morosoRaw, vendedor, estadoRaw] = row

    const telA_clean = cleanPhone(telA)
    const telB_clean = cleanPhone(telB)

    // Si solo hay un teléfono en col A → va a telefono; si solo en col B → va a telefono; si ambos → A=telefono, B=telefono_casa
    const telefono = telB_clean ?? telA_clean
    const telefono_casa = telB_clean && telA_clean ? telA_clean : null

    const email = cleanEmail(emailRaw)
    const saldo_actual = parseMonto(saldoRaw)
    const monto_moroso = parseMonto(morosoRaw)
    const { estado_cuenta, estado_operativo, estado_morosidad, dias_atraso, estado_cuenta_raw } = parseEstado(estadoRaw)

    const esCargodeVuelta = estado_cuenta === 'cargo_de_vuelta'

    const payload: Record<string, unknown> = {
      nombre: nombre.trim() || null,
      apellido: apellido.trim() || null,
      email,
      telefono,
      telefono_casa,
      // Cargo de vuelta: NO tocar saldo — lo gestiona el caso en cargo_vuelta_cases
      ...(esCargodeVuelta ? {} : {
        saldo_actual,
        monto_moroso,
        dias_atraso,
      }),
      estado_cuenta,
      estado_operativo,
      estado_morosidad,
      estado_cuenta_raw,
      codigo_vendedor_hycite: vendedor.trim() || null,
      origen: 'hycite_import',
      updated_at: new Date().toISOString(),
    }

    if (DRY_RUN) {
      const saldoInfo = esCargodeVuelta
        ? '⏭ saldo omitido (cargo de vuelta)'
        : `saldo: $${saldo_actual} | moroso: $${monto_moroso}`
      console.log(`  ${hyciteId} | ${nombre} ${apellido} | tel: ${telefono ?? '—'} | ${saldoInfo} | ${estado_cuenta}`)
      updated++
      continue
    }

    const { error } = await supabase
      .from('clientes')
      .update(payload)
      .eq('hycite_id', hyciteId)
      .eq('org_id', orgId)

    if (error) {
      console.error(`  ❌ ${hyciteId} ${nombre} ${apellido}: ${error.message}`)
      errors.push(hyciteId)
    } else {
      console.log(`  ✅ ${hyciteId} | ${nombre} ${apellido}`)
      updated++
    }
  }

  console.log(`\n─────────────────────────────────────────`)
  if (DRY_RUN) {
    console.log(`📋 DRY-RUN: ${updated} registros listos para actualizar.`)
    console.log(`   Ejecuta sin --dry-run para aplicar los cambios.`)
  } else {
    console.log(`✅ Actualizados: ${updated}`)
    if (notFound > 0) console.log(`⚠  No encontrados: ${notFound}`)
    if (errors.length > 0) console.log(`❌ Errores: ${errors.join(', ')}`)
  }
}

run().catch(e => { console.error(e); process.exit(1) })
